code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100vw;
  height: 100vh;
  background: #000;
  font-family: "Arame";
}

p {
  text-transform: uppercase;
}

.container {
  width: 100%;
  height: 100vh;
  display: flex;
  flex-direction: column;
  gap: 0.25em;
}

nav {
  width: 100%;
  flex: 1;
  display: flex;
  gap: 0.25em;
  padding: 0.25em 0 0 0;
  background: #000;
}

nav > div {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1em 2em;
  background: #fff;
  color: #000;
  border-radius: 10px;
}

.nav-1 {
  flex: 3;
}

.nav-2 {
  flex: 2;
}

.nav-3 {
  flex: 3;
}

.content-wrapper {
  flex: 12;
  width: 100%;
  height: 100%;
  display: flex;
  padding: 0 0 0.5em 0;
  gap: 0.25em;
  background: #000;
}

.content-wrapper .col {
  border-radius: 10px;
  background: #fff;
  padding: 3em 2em;
}

.col-1 {
  flex: 5.5;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.col-2 {
  flex: 3;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.col-1 p {
  font-size: 12px;
  line-height: 1;
}

.col-1 .hero-img {
  width: 100%;
  height: 180px;
  border-radius: 10px;
  overflow: hidden;
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.col-1 h1 {
  font-family: "Mars Model";
  font-size: 100px;
  text-transform: uppercase;
  line-height: 0.8;
}

.numbers {
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.numbers p {
  flex: 1;
}

.numbers p:nth-child(3) {
  text-align: right;
}

.numbers .hr {
  flex: 5;
  width: 100%;
  height: 2px;
  background: #000;
}

.cta {
  width: 100%;
}

.cta .cta-btn {
  background: #000;
  color: #fff;
  padding: 1.5em;
  border-radius: 10px;
  display: flex;
  justify-content: flex-end;
}

.cta-btn h3 {
  font-family: "Mars Model";
  font-size: 40px;
  text-transform: uppercase;
  line-height: 1;
}

h3 ion-icon {
  position: relative;
  top: 7.5px;
}

.p-img {
  position: relative;
  width: 70%;
  height: 160px;
  left: 50%;
  transform: translateX(-50%) rotate(-10deg);
}

.p-img-border {
  position: absolute;
  top: 10px;
  left: 10px;
  width: 100%;
  height: 100%;
  border: 2px solid #000;
  border-radius: 10px;
}

.p-img-wrap {
  position: absolute;
  width: 100%;
  height: 100%;
  border-radius: 10px;
  overflow: hidden;
  z-index: 2;
}

.p-info {
  width: 100%;
  display: flex;
  justify-content: space-between;
}

.img {
  display: flex;
  flex-direction: column;
}

.img-data {
  display: flex;
  justify-content: space-between;
}

.img-name p {
  font-size: 24px;
}

.img-info p {
  font-size: 12px;
  line-height: 1;
  text-align: right;
}

.img .hr {
  width: 100%;
  height: 2px;
  margin: 1em 0;
  background: #000;
}

.price {
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
}

p#amount {
  font-size: 40px;
}

.carousel {
  width: 100%;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.arrow {
  font-size: 32px;
  padding: 1em;
  border-radius: 10px;
  background: #000;
  color: #fff;
}
